import { describe, it } from 'vitest'
import helper from './_test-helper.ts'
import assert from 'node:assert'

describe('big-simple-query', () => {
  const Query = helper.pg.Query
  /*
  Test to trigger a bug.

  I really dont know what's wrong but it seams that its triggered by multable big queryies with supplied values.
  The test bellow can trigger the bug.
*/

  // Big query with a where clouse from supplied value
  const big_query_rows_1: unknown[] = []
  const big_query_rows_2: unknown[] = []
  const big_query_rows_3: unknown[] = []

  // Works
  it('big simple query 1', async function () {
    const client = helper.client()
    await helper.createPersonTable(client)
    return new Promise<void>((resolve) => {
      client
        .query(
          new Query(
            "select '' as bla from person where name = '' or 1 = 1"
          )
        )
        .on('row', function (row) {
          big_query_rows_1.push(row)
        })
        .on('error', function (error) {
          console.log('big simple query 1 error')
          console.log(error)
        })
      client.on('drain', () => {
        client.end()
        resolve()
      })
    })
  })

  // Works
  it('big simple query 2', async function () {
    const client = helper.client()
    await helper.createPersonTable(client)
    return new Promise<void>((resolve) => {
      client
        .query(
          new Query(
            "select '' as bla from person where name = $1 or 1 = 1",
            ['']
          )
        )
        .on('row', function (row) {
          big_query_rows_2.push(row)
        })
        .on('error', function (error) {
          console.log('big simple query 2 error')
          console.log(error)
        })
      client.on('drain', () => {
        client.end()
        resolve()
      })
    })
  })

  // Fails most of the time with 'invalid byte sequence for encoding "UTF8": 0xb9' or 'insufficient data left in message'
  // If test 1 and 2 are commented out it works
  it('big simple query 3', async function () {
    const client = helper.client()
    await helper.createPersonTable(client)
    return new Promise<void>((resolve) => {
      client
        .query(
          new Query(
            "select '' as bla from person where name = $1 or 1 = 1",
            ['']
          )
        )
        .on('row', function (row) {
          big_query_rows_3.push(row)
        })
        .on('error', function (error) {
          console.log('big simple query 3 error')
          console.log(error)
        })
      client.on('drain', () => {
        client.end()
        resolve()
      })
    })
  })

  process.on('exit', function () {
    assert.equal(big_query_rows_1.length, 26, 'big simple query 1 should return 26 rows')
    assert.equal(big_query_rows_2.length, 26, 'big simple query 2 should return 26 rows')
    assert.equal(big_query_rows_3.length, 26, 'big simple query 3 should return 26 rows')
  })

  const runBigQuery = function (client: InstanceType<typeof helper.Client>): void {
    client.query(
      "select '' as bla from person where name = $1 or 1 = 1",
      [''],
      function (err: Error | undefined, result: { rows: unknown[] }) {
        if (err != null) {
          console.log(err)
          throw err
        }
        assert.lengthIs(result.rows, 26)
      }
    )
  }

  it('many times', async function () {
    const client = helper.client()
    await helper.createPersonTable(client)
    return new Promise<void>((resolve) => {
      for (let i = 0; i < 20; i++) {
        runBigQuery(client)
      }
      client.on('drain', function () {
        client.end()
        setTimeout(function () {
          resolve()
          // let client disconnect fully
        }, 100)
      })
    })
  })
})
